class Command(BaseCommand):
    help = 'Seed all FSRB member countries into the database'

    def handle(self, *args, **options):
        created_count = 0
        updated_count = 0

        for data in COUNTRIES:
            obj, created = Country.objects.update_or_create(
                iso_code=data['iso_code'],
                defaults=data,
            )
            if created:
                created_count += 1
            else:
                updated_count += 1

        self.stdout.write(
            self.style.SUCCESS(
                f'Done. Created: {created_count}, Updated: {updated_count}. '
                f'Total processed: {len(COUNTRIES)}'
            )
        )
